#include <cstdio>
#include <cstdlib>
#include <omp.h>

#define INF 1000000

int main(int argc, char *argv[]) {
    if (argc != 3) {
        printf("Usage: %s <num_nodes> <input_file>\n", argv[0]);
        return 1;
    }

    int n = atoi(argv[1]);
    const char *input_file = argv[2];

    int *dist = (int *)malloc(n * n * sizeof(int));
    if (!dist) {
        printf("Failed to allocate memory\n");
        return 1;
    }

    FILE *fp = fopen(input_file, "r");
    if (!fp) {
        printf("Failed to open input file %s\n", input_file);
        free(dist);
        return 1;
    }

    for (int i = 0; i < n * n; i++) {
        if (fscanf(fp, "%d", &dist[i]) != 1) {
            printf("Failed to read input data\n");
            fclose(fp);
            free(dist);
            return 1;
        }
    }
    fclose(fp);

    // Floyd-Warshall algorithm with OpenMP parallelization
    for (int k = 0; k < n; k++) {
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; i++) {
            int ik = dist[i * n + k];
            for (int j = 0; j < n; j++) {
                int kj = dist[k * n + j];
                int ij = dist[i * n + j];
                if (ik + kj < ij) {
                    dist[i * n + j] = ik + kj;
                }
            }
        }
    }

    // Output the result matrix
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            printf("%d ", dist[i * n + j]);
        }
        printf("\n");
    }

    free(dist);
    return 0;
}
